def render_confidence_bars(scores: dict):
    for name, score in scores.items():
        pct = score * 100
        st.markdown(f"""
        <div class="conf-wrap">
            <div class="conf-row">
                <span>{name}</span>
                <span class="conf-val">{pct:.1f}%</span>
            </div>
            <div class="conf-track">
                <div class="conf-fill" style="width:{pct}%;"></div>
            </div>
        </div>
        """, unsafe_allow_html=True)


def fetch_explanation(class_idx: int, confidence: float) -> str:
    try:
        resp = requests.post(
            f"{API_URL}/explain",
            json={"class_idx": class_idx, "confidence": confidence,
                  "gemini_api_key": st.session_state.get("gemini_key", ""),
                  "language": st.session_state.get("language", "English")},
            timeout=30,
        )
        if resp.ok:
            return resp.json().get("explanation", "")
    except Exception as e:
        st.warning(f"Explanation error: {e}")
    return ""


def fetch_eli5(class_idx: int, confidence: float) -> str:
    try:
        resp = requests.post(
            f"{API_URL}/explain_eli5",
            json={"class_idx": class_idx, "confidence": confidence,
                  "gemini_api_key": st.session_state.get("gemini_key", ""),
                  "language": st.session_state.get("language", "English")},
            timeout=30,
        )
        if resp.ok:
            return resp.json().get("explanation", "")
    except Exception as e:
        pass
    return ""


def fetch_chat(question: str, class_idx: int, confidence: float, history: list) -> str:
    try:
        resp = requests.post(
            f"{API_URL}/chat",
            json={
                "question": question,
                "class_idx": class_idx,
                "confidence": confidence,
                "gemini_api_key": st.session_state.get("gemini_key", ""),
                "language": st.session_state.get("language", "English"),
                "history": history,
            },
            timeout=30,
        )
        if resp.ok:
            return resp.json().get("answer", "")
    except Exception as e:
        pass
    return "Sorry, I couldn't reach the AI right now. Please try again."


def fetch_region_explanation(img_b64: str, x: int, y: int) -> str:
    try:
        resp = requests.post(
            f"{API_URL}/explain_region",
            json={
                "img_b64": img_b64,
                "x": x, "y": y,
                "gemini_api_key": st.session_state.get("gemini_key", ""),
                "language": st.session_state.get("language", "English")
            },
            timeout=30,
        )
        if resp.ok:
            return resp.json().get("explanation", "")
    except Exception as e:
        pass
    return "Region analysis unavailable."


def thinking_animation(messages: list, placeholder):
    """Cycles through thinking messages with animated dots."""
    for msg in messages:
        placeholder.markdown(f"""
        <div class="thinking-card">
            <div style="font-size:1.3rem; margin-bottom:12px;">{msg}</div>
            <div class="thinking-dots">
                <span></span><span></span><span></span>
            </div>
        </div>
        """, unsafe_allow_html=True)
        time.sleep(1.2)


def b64_to_pil(b64_str: str) -> Image.Image:
    return Image.open(BytesIO(base64.b64decode(b64_str)))


